"use client";
import { usePlayerStore } from '@/store/usePlayerStore';
import { Play } from 'lucide-react';

export default function SongCard({ id, title, thumbnail }: { id: string, title: string, thumbnail: string }) {
  const setTrack = usePlayerStore((state) => state.setTrack);

  const cleanThumbnail = thumbnail.includes('hqdefault') 
    ? `https://img.youtube.com/vi/${id}/mqdefault.jpg` : thumbnail;

  const handlePlay = (e: React.MouseEvent) => {
    e.stopPropagation(); // CRITICAL: Stops double-firing
    setTrack(id, { title, thumbnail: cleanThumbnail });
  };

  return (
    <div 
      onClick={() => setTrack(id, { title, thumbnail: cleanThumbnail })}
      className="bg-[#181818] p-4 rounded-md hover:bg-[#282828] transition group relative cursor-pointer"
    >
      <div className="relative aspect-square mb-4">
        <img src={cleanThumbnail} alt={title} className="w-full h-full object-cover rounded shadow-lg" />
        <div className="absolute bottom-2 right-2 opacity-0 group-hover:opacity-100 translate-y-2 group-hover:translate-y-0 transition">
          <button 
            onClick={handlePlay}
            className="p-3 bg-[#1ed760] rounded-full shadow-xl hover:scale-105 transition"
          >
            <Play className="text-black fill-black" size={24} />
          </button>
        </div>
      </div>
      <h3 className="font-bold truncate text-white">{title}</h3>
      <p className="text-sm text-zinc-400">YouTube Video</p>
    </div>
  );
}